/**
 * Minimal Budget Comprehensive Test - Isolate Jest error
 */

import React from 'react';
import { render, screen } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { describe, it, expect, beforeEach, jest } from '@jest/globals';
import '@testing-library/jest-dom';
import userEvent from '@testing-library/user-event';

// Import the BudgetInner component (which should map to mock via Jest config)
import BudgetInner from '../../client/src/pages/manager/budget';

// Mock all the dependencies just like the comprehensive test
jest.mock('@/hooks/use-language', () => ({
  useLanguage: () => ({
    t: (key: string) => key,
  }),
}));

jest.mock('@/hooks/use-toast', () => ({
  useToast: () => ({
    toast: jest.fn(),
  }),
}));

jest.mock('wouter', () => ({
  useLocation: () => ['/', jest.fn()],
}));

describe('Budget Comprehensive Minimal Tests', () => {
  let queryClient: QueryClient;
  
  beforeEach(() => {
    queryClient = new QueryClient({
      defaultOptions: {
        queries: { retry: false },
        mutations: { retry: false },
      },
    });
    jest.clearAllMocks();
    
    // Mock fetch
    global.fetch = jest.fn().mockResolvedValue({
      json: () => Promise.resolve({}),
      ok: true,
    });
  });

  it('should render budget component', () => {
    render(
      <QueryClientProvider client={queryClient}>
        <BudgetInner buildingId="building-123" organizationId="org-123" />
      </QueryClientProvider>
    );

    expect(screen.getByTestId('budget-page')).toBeInTheDocument();
  });

  it('should render settings button', () => {
    render(
      <QueryClientProvider client={queryClient}>
        <BudgetInner buildingId="building-123" organizationId="org-123" />
      </QueryClientProvider>
    );

    expect(screen.getByTestId('button-budget-settings')).toBeInTheDocument();
  });
});